!function(){return function e(n,o,t){function i(r,s){if(!o[r]){if(!n[r]){var d="function"==typeof require&&require;if(!s&&d)return d(r,!0);if(a)return a(r,!0);var c=new Error("Cannot find module '"+r+"'");throw c.code="MODULE_NOT_FOUND",c}var l=o[r]={exports:{}};n[r][0].call(l.exports,function(e){return i(n[r][1][e]||e)},l,l.exports,e,n,o,t)}return o[r].exports}for(var a="function"==typeof require&&require,r=0;r<t.length;r++)i(t[r]);return i}}()({1:[function(e,n,o){"use strict";Object.defineProperty(o,"__esModule",{value:!0}),o.growthMarketingCoordinator=void 0;o.growthMarketingCoordinator={title:"Growth Marketing Coordinator",header:'\n    <p>\n    Reports to: Growth Marketing Coordinator<br> \n    Department: Site & Growth Marketing<br> \n    Reports: None<br> \n    FLSA Status: Non-Exempt<br> \n    </p>\n\n    <h5>\n    To be considered for this role, please complete the Google Form Application here:\n    </h5>\n\n    <p>\n    <a href="https://forms.gle/AhgpUnuKC7odmVyv8" target="_blank">https://forms.gle/AhgpUnuKC7odmVyv8</a>\n    </p>\n\n    <h3>Position Overview</h3>\n    \n    <p>\n    We’re looking for a Marketing Coordinator to help keep Tea Collection’s marketing efforts organized, on track, and running smoothly. This role supports the execution and optimization of our marketing programs across digital advertising and print catalogs.\n    </p>\n\n    <p>\n    You’ll work closely with Marketing, Creative, Site, Product, and external partners to support campaign execution, performance tracking, and testing. This is a great opportunity for someone who enjoys both creative and analytical work, thrives in a fast-paced environment, and wants to grow hands-on marketing experience with strong mentorship.\n    </p>\n\n    <p>\n    This is a hybrid role. Bay Area–based team members work from our Emeryville office at least one day per week. Remote team members are expected to travel to the office at least twice a year. The Coordinator must be accessible via video and messaging platforms during standard Pacific Time business hours.\n    </p>\n\n',pay:"\n    <h3>Pay Range:</h3>\n    <p>$53,000-58,000 Salary</p>\n    ",duties:[{header:"Campaign Execution & Coordination:",list:["Support the day-to-day execution of marketing campaigns across digital advertising and catalogs. Partner with Creative and cross-functional teams to ensure assets are planned, delivered, and launched accurately and on time."]},{header:"Channel & Partner Support:",list:["Coordinate with external partners such as advertising platform representatives and catalog vendors to ensure timelines, assets, and execution are aligned."]},{header:"Testing & Optimization:",list:["Support testing across creative, copy, and targeting strategies. Track results and help summarize learnings to inform future optimizations and improvements."]},{header:"Reporting & Performance Analysis:",list:["Pull and organize weekly, monthly, and quarterly performance data across marketing channels. Support reporting and hindsighting to help the team understand trends, pacing, and opportunities."]},{header:"Project & Process Management:",list:["Help keep marketing calendars, trackers, timelines, and documentation organized and up to date. Support smooth collaboration across teams by ensuring clarity, alignment, and follow-through on campaign deliverables."]}],who:["Curious, organized, and excited to grow in the marketing space","A proactive problem-solver and clear communicator","Equally comfortable with both creative and analytical tasks","Detail-oriented with strong organizational skills","Thrive in fast-paced, collaborative environments"],qualifications:["0–2 years of experience in digital marketing, eCommerce, or a related role","Hands-on experience with paid media platforms (Meta Ads + Google Ads)","Proficient using Excel/Google Sheets for data tracking and reporting","Bachelor's degree in Marketing, Advertising, or related with a strong academic track record"],footer:"\n    <h3>Expectations for All Employees:</h3>\n    \n    <p>\n    Supports Tea Collection’s mission, vision, and values by embodying excellence and competence, collaboration, innovation, respect, personalization, community commitment, and accountability.\n    </p>\n    \n    <p>\n    Note: Nothing in this job description restricts management’s right to assign or reassign duties and responsibilities to this job at any time. Tea Collection  is an Equal Opportunity Employer. We celebrate diversity and are committed to creating an inclusive environment for all employees. We do not discriminate based upon race, religion, color, national origin, sex, sexual orientation, gender identity, age, status as a protected veteran, status as an individual with a disability, or other applicable legally protected characteristics.\n    </p>\n    "}},{}],2:[function(e,n,o){"use strict";Object.defineProperty(o,"__esModule",{value:!0}),o.officeCommunityCoordinator=void 0;o.officeCommunityCoordinator={title:"Office & Community Coordinator",header:'\n    <p>\n    Reports to: Director of Finance & Accounting<br> \n    Department: Finance & Accounting<br> \n    Reports: None<br> \n    FLSA Status: Non-Exempt<br> \n    </p>\n\n    <h5>\n    To be considered for this role, please complete the Google Form Application here:\n    </h5>\n\n    <p>\n    <a href="https://docs.google.com/forms/d/e/1FAIpQLScXxFe53qiorXm0NXsqD9a210LtmfC33WmcIt3Z1QTFsbT_xQ/viewform?usp=publish-editor" target="_blank">https://docs.google.com/forms/d/e/1FAIpQLScXxFe53qiorXm0NXsqD9a210LtmfC33WmcIt3Z1QTFsbT_xQ/viewform?usp=publish-editor</a>\n    </p>\n\n    <h3>About the Role:</h3>\n    \n    <p>\n    This position is a part-time, in office position. Typical office schedule: 9am-5pm on all-company office days (initially one day/week), approximately 4-6 hours on all other days. Specific hours are within business hours, but flexible based on business needs and advanced manager approval..\n    </p>\n\n    <h3>Overview:</h3>\n\n    <p>\n    The Office/Community Coordinator is responsible for our office, ensuring our team, both remote and local, have the resources and environment needed to be successful.\n    </p>\n\n',pay:"\n    <h3>Pay Range:</h3>\n    <p>$22-26 per hour</p>\n    ",duties:[{header:"Office Management:",list:["Proactive communication and support for anyone who works in or visits our office to ensure a welcoming environment","Keep office organized and professional. Maintain/manage off site storage. Prioritize a positive, productive, and brand right environment.","Manage inbound and outbound mail and shipments","Coordinate with office related services including janitorial, landlord, security, groceries, and other","Coordinate with landlord and/or contractors for any office needs","Manage parking assignments and security procedures including distributing access codes/keys, keeping technology equipment and confidential documentation secure in the office","Support for community building activities including delivering supplies, organizing events and monthly staff meetings","Facilitate Tea meetings, events, interview schedules and/or appointments. Manage internal documents and databases, and create standardized organization systems","Prepare office for photo shoots and then ensure office is ready for regular work after photo shoots are completed","Provide ad hoc support during Photoshoots including coordinating basic logistics, cleaning services, food and permits as needed.","Occasional support for Leadership Team members on an as needed basis; direction given each week. For example: facilitate all staff meetings (materials, technology, scheduling, etc)","Responsible for adhering to budget and reporting results to finance"]},{header:"Community Building/Support:",list:["Plan community building activities and events for the team including periodic off-site meetings and retreats.","Primary point person on Corporate Social Responsibility efforts including volunteering, donations, and other giveback opportunities.","Create and distribute product discounts and allowances to employees and vendors","Organize monthly company lunches and regular educational/development opportunities","Facilitate monthly company values nomination process","Celebrate and recognize Birthdays/Anniversaries/Life Events","Plan and execute meetings including projection and video calls for remote team members. Ensure remote team is able to engage fully during in office work days","Plan and support remote team members when visiting the Bay Area, plan and execute holiday cards/gifts to our team, vendors, and partners","Facilitate community volunteer opportunities","Facilitate and execute Donation strategy with input from Marketing & Finance"]},{header:"Special Projects:",list:["As needed, the coordinator will support the Tea team with projects, especially as projects relate to our team, office, and broader community including sample sales, etc.","Support HR with various employee actives (ie Day 1 Onboarding & Welcome) and project to support Tea culture and engagement activities as needed","Office décor, organization or space planning as needs and seasons change","Support team with inbound and outbound packages, including samples and items being shipped back and forth to production vendors. Ensure office stays organized including samples, supporting samples when/as needed"]}],who:[""],qualifications:["1-3 Years of Admin/Coordinator or Office Management (or equivalent) experience","Exceptional attention to detail, organizational skills, and affinity for order and accuracy","Physically able to move and maintain sample bins, boxes and racks","Ability to work independently with minimal instruction and supervision","Must have excellent time management skills, be self-sufficient and ability to adapt as needed","Exceptional at creating and maintaining calendars and tracking documents/items","Creative problem-solver","Expert in video conferencing tools, Excel, Slack & Google Docs","Experience in hospitality to create warm, welcoming environment"],footer:"\n    <h3>Expectations for All Employees:</h3>\n    \n    <p>\n    Supports the organization’s mission, vision, and values by exhibiting the following behaviors: excellence and competence, collaboration, innovation, respect, personalization, commitment to our community, and accountability and ownership.\n    </p>\n    "}},{}],3:[function(e,n,o){"use strict";Object.defineProperty(o,"__esModule",{value:!0}),o.jobs=void 0;var t=e("./job-descriptions/office-community-coordinator.js"),i=e("./job-descriptions/growth-marketing-coordinator.js");o.jobs=[i.growthMarketingCoordinator,t.officeCommunityCoordinator]},{"./job-descriptions/growth-marketing-coordinator.js":1,"./job-descriptions/office-community-coordinator.js":2}]},{},[3]);